272:   HandleMark hm(Thread::current());
273:   ResourceMark rm;
274: 
275:   // We have to ensure that we finish scanning the root regions
276:   // before the next GC takes place. To ensure this we have to
277:   // make sure that we do not join the STS until the root regions
278:   // have been scanned. If we did then it's possible that a
279:   // subsequent GC could block us from joining the STS and proceed
280:   // without the root regions have been scanned which would be a
281:   // correctness issue.
282:   //
283:   // So do not return before the scan root regions phase as a GC waits for a
284:   // notification from it.
285:   //
286:   // For the same reason ConcurrentGCBreakpoints (in the phase methods) before
287:   // here risk deadlock, because a young GC must wait for root region scanning.
288:   //
289:   // We can not easily abort before root region scan either because of the
290:   // reasons mentioned in G1CollectedHeap::abort_concurrent_cycle().
291: 
292:   // Phase 1: Scan root regions.
293:   if (phase_scan_root_regions()) return;
294: 
295:   // Phase 2: Actual mark loop.
296:   if (phase_mark_loop()) return;
297: 
298:   // Phase 3: Rebuild remembered sets and scrub dead objects.
299:   if (phase_rebuild_and_scrub()) return;
300: 
301:   // Phase 4: Wait for Cleanup.
302:   if (phase_delay_to_keep_mmu_before_cleanup()) return;
303: 
304:   // Phase 5: Cleanup pause
305:   if (phase_cleanup()) return;
306: 
307:   // Phase 6: Clear CLD claimed marks.
308:   if (phase_clear_cld_claimed_marks()) return;
309: 
310:   // Phase 7: Clear bitmap for next mark.
