1213:   struct G1OnRegionClosure : public G1HeapRegionClosure {
1214:     G1CollectedHeap* _g1h;
1215:     G1ConcurrentMark* _cm;
1216:     // The number of regions actually selected for rebuild.
1217:     uint _num_selected_for_rebuild;
1218: 
1219:     size_t _freed_bytes;
1220:     uint _num_old_regions_removed;
1221:     uint _num_humongous_regions_removed;
1222:     G1FreeRegionList* _local_cleanup_list;
1223: 
1224:     G1OnRegionClosure(G1CollectedHeap* g1h,
1225:                       G1ConcurrentMark* cm,
1226:                       G1FreeRegionList* local_cleanup_list) :
1227:       _g1h(g1h),
1228:       _cm(cm),
1229:       _num_selected_for_rebuild(0),
1230:       _freed_bytes(0),
1231:       _num_old_regions_removed(0),
1232:       _num_humongous_regions_removed(0),
1233:       _local_cleanup_list(local_cleanup_list) {}
1234: 
1235:     void reclaim_empty_humongous_region(G1HeapRegion* hr) {
1236:       assert(!hr->has_pinned_objects(), "precondition");
1237:       assert(hr->is_starts_humongous(), "precondition");
1238: 
1239:       auto on_humongous_region = [&] (G1HeapRegion* hr) {
1240:         assert(hr->used() > 0, "precondition");
1241:         assert(!hr->has_pinned_objects(), "precondition");
1242:         assert(hr->is_humongous(), "precondition");
1243: 
1244:         _num_humongous_regions_removed++;
1245:         _freed_bytes += hr->used();
1246:         hr->set_containing_set(nullptr);
1247:         hr->clear_cardtable();
1248:         _g1h->concurrent_mark()->clear_statistics(hr);
1249:         G1HeapRegionPrinter::mark_reclaim(hr);
1250:         _g1h->free_humongous_region(hr, _local_cleanup_list);
1251:       };
1252: 
1253:       _g1h->humongous_obj_regions_iterate(hr, on_humongous_region);
1254:     }
1255: 
1256:     void reclaim_empty_old_region(G1HeapRegion* hr) {
1257:       assert(hr->used() > 0, "precondition");
1258:       assert(!hr->has_pinned_objects(), "precondition");
1259:       assert(hr->is_old(), "precondition");
1260: 
1261:       _num_old_regions_removed++;
1262:       _freed_bytes += hr->used();
1263:       hr->set_containing_set(nullptr);
1264:       hr->clear_cardtable();
1265:       _g1h->concurrent_mark()->clear_statistics(hr);
1266:       G1HeapRegionPrinter::mark_reclaim(hr);
1267:       _g1h->free_region(hr, _local_cleanup_list);
1268:     }
