1270:     bool do_heap_region(G1HeapRegion* hr) override {
1271:       G1RemSetTrackingPolicy* tracker = _g1h->policy()->remset_tracker();
1272:       if (hr->is_starts_humongous()) {
1273:         // The liveness of this humongous obj decided by either its allocation
1274:         // time (allocated after conc-mark-start, i.e. live) or conc-marking.
1275:         const bool is_live = _cm->top_at_mark_start(hr) == hr->bottom()
1276:                              || _cm->contains_live_object(hr->hrm_index());
1277:         if (is_live) {
1278:           const bool selected_for_rebuild = tracker->update_humongous_before_rebuild(hr);
1279:           auto on_humongous_region = [&] (G1HeapRegion* hr) {
1280:             if (selected_for_rebuild) {
1281:               _num_selected_for_rebuild++;
1282:             }
1283:             _cm->update_top_at_rebuild_start(hr);
1284:           };
1285: 
1286:           _g1h->humongous_obj_regions_iterate(hr, on_humongous_region);
1287:         } else {
1288:           reclaim_empty_humongous_region(hr);
1289:         }
1290:       } else if (hr->is_old()) {
1291:         hr->note_end_of_marking(_cm->top_at_mark_start(hr), _cm->live_bytes(hr->hrm_index()));
1292: 
1293:         if (hr->live_bytes() != 0) {
1294:           if (tracker->update_old_before_rebuild(hr)) {
1295:             _num_selected_for_rebuild++;
1296:           }
1297:           _cm->update_top_at_rebuild_start(hr);
1298:         } else {
1299:           reclaim_empty_old_region(hr);
1300:         }
